// ─────────────────────────────────────────────
// VHSYS :: employers_general_data
// Rota   : POST /employers_general_data
// Fase 4 : Fluxo EMPLOYERS completo
// ─────────────────────────────────────────────
// Input  : { data: { employees: [{ Id, Nome, Cpf, DataAdmissao, ... }] } }
// Output : { message: string, employees_updated: number } HTTP 201
// Banco  : UPSERT funcionarios por id_funcionario
// Chave  : id_funcionario (campo Id da API)
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

if (!body.data) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required field: data' }
  };
}

if (!body.data.employees || !Array.isArray(body.data.employees)) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing or invalid employees array' }
  };
}

const employees = body.data.employees;

if (employees.length === 0) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Employees array cannot be empty' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_general_data',
  event: 'input_validated',
  employees_count: employees.length,
  level: 'info'
}));

return { _valid: true, employees };

// Transform e normaliza dados dos funcionários
// Expande cada funcionário para um item separado
const ctx = $input.first().json;
const employees = ctx.employees;

// Helper para formatar CPF
function formatCpf(cpf) {
  if (!cpf) return '';
  const cleaned = String(cpf).replace(/\D/g, '');
  if (cleaned.length === 11) {
    return cleaned.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');
  }
  return cpf;
}

// Helper para converter data
function parseDate(dateStr) {
  if (!dateStr) return null;
  // Aceita formatos: YYYY-MM-DD, DD/MM/YYYY, etc.
  const date = new Date(dateStr);
  return isNaN(date.getTime()) ? null : date.toISOString().split('T')[0];
}

// Helper para converter salário
function parseSalary(salary) {
  if (!salary) return 0;
  const cleaned = String(salary).replace(/[^0-9.,]/g, '').replace(',', '.');
  const num = parseFloat(cleaned);
  return isNaN(num) ? 0 : num;
}

const transformedEmployees = employees.map(emp => {
  const id = String(emp.Id || '').trim();

  if (!id) {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      route: 'employers_general_data',
      event: 'employee_skipped_no_id',
      employee_data: emp,
      level: 'warn'
    }));
    return null;
  }

  return {
    id_funcionario: id,
    nome: String(emp.Nome || '').trim(),
    cpf: formatCpf(emp.Cpf),
    data_admissao: parseDate(emp.DataAdmissao),
    data_demissao: parseDate(emp.DataDemissao),
    cargo: String(emp.Cargo || '').trim(),
    salario: parseSalary(emp.Salario),
    status_funcionario: String(emp.Status || 'Ativo').trim()
  };
}).filter(emp => emp !== null);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_general_data',
  event: 'employees_transformed',
  valid_employees: transformedEmployees.length,
  level: 'info'
}));

return transformedEmployees;

// Conta registros afetados e constrói resposta
const affectedRecords = $input.all()
  .filter(item => item.json && item.json.id_funcionario)
  .length;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_general_data',
  event: 'employees_upserted',
  employees_updated: affectedRecords,
  level: 'info'
}));

// statusCode 201 — preserva compatibilidade com Flask original
return {
  statusCode: 201,
  body: {
    message: 'Employees data updated successfully',
    employees_updated: affectedRecords
  }
};

// Erro de validação
const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_general_data',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not update employees data' }
};

// Return the response data as-is
const response = $input.first().json;
return response;
